const text = $json.output?.[0]?.content?.[0]?.text ?? "";

const cleaned = text
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let parsed;

try {
  parsed = JSON.parse(cleaned);
} catch (error) {
  parsed = {
    ai_category: "general_question",
    ai_urgency: "medium",
    ai_sentiment: "neutral",
    recommended_queue: "tier1_support",
    escalation_flag: false,
    confidence_score: 0.25,
    triage_reason: "Fallback applied because AI returned invalid JSON",
    fallback_applied: true
  };
}

return {
  json: {
    ...$json,
    ...parsed
  }
};

const urgency = $json.ai_urgency;
const isEnterprise = $json.customer_tier === "enterprise";
const escalation = $json.escalation_flag === true;

// VIP flag
const vip_flag = isEnterprise;

// SLA risk calculation
let sla_risk = "low";

if (urgency === "critical" || escalation) {
  sla_risk = "high";
} else if (urgency === "high") {
  sla_risk = "medium";
}

// Priority scoring
let priority_score = 30;

if (urgency === "critical") {
  priority_score = 100;
} else if (escalation) {
  priority_score = 90;
} else if (urgency === "high") {
  priority_score = 80;
} else if (urgency === "medium") {
  priority_score = 60;
}

// Enterprise customers get a boost
if (vip_flag) {
  priority_score += 10;
}

if (priority_score > 100) {
  priority_score = 100;
}

return {
  json: {
    ...$json,
    vip_flag,
    sla_risk,
    priority_score
  }
};
